import React, { useState } from 'react';
import Drawer from '@material-ui/core/Drawer';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import Typography from '@material-ui/core/Typography';
import IconButton from '@material-ui/core/IconButton';
import MenuIcon from '@material-ui/icons/Menu';
import { Link } from 'react-router-dom';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  mainMenuItem: {
    fontSize: '1.2rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
  subMenuItem: {
    fontSize: '1rem',
    paddingTop: 1,
    paddingBottom: 1,
  },
}));

const DrawerMenu = ({ categories }) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const classes = useStyles();

  const handleDrawerOpen = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  const generateMenuItems = () => {
    if (!Array.isArray(categories) || categories.length === 0) {
      return null;
    }

    return (
      <List>
        {categories.map((category) => {
          const { _id, mainMenu, subMenu } = category;

          if (!_id || !mainMenu) {
            return null;
          }

          return (
            <div key={_id}>
              <ListItem
                button
                component={Link}
                to={`/${mainMenu}`}
                onClick={handleDrawerClose}
                className={classes.mainMenuItem} // Apply styles here
              >
                <Typography variant="h6">
                  {mainMenu}
                </Typography>
              </ListItem>
              {Array.isArray(subMenu) && subMenu.length > 0 && (
                <List component="div" disablePadding>
                  {subMenu.map((subItem) => {
                    if (!subItem) {
                      return null;
                    }

                    const subItemId = subItem._id || '';
                    const subItemText = subItem || '';

                    return (
                      <ListItem
                        key={subItemId}
                        button
                        component={Link}
                        to={`/${mainMenu}/${subItemId}`}
                        onClick={handleDrawerClose}
                        className={classes.subMenuItem} // Apply styles here
                      >
                        <Typography variant="body1">
                          {subItemText}
                        </Typography>
                      </ListItem>
                    );
                  })}
                </List>
              )}
            </div>
          );
        })}
      </List>
    );
  };


  return (
    <div>
      <IconButton
        edge="start"
        color="inherit"
        aria-label="menu"
        onClick={handleDrawerOpen}
      >
        <MenuIcon />
      </IconButton>
      <Drawer anchor="top" open={isDrawerOpen} onClose={handleDrawerClose}>
        {generateMenuItems()}
      </Drawer>
    </div>
  );
};

export default DrawerMenu;
